import React, { useState } from 'react';
import {
    Container,
    Paper,
    Typography,
    TextField,
    Slider,
    Box,
    Grid,
    Button,
    Card,
    CardContent,
    Alert,
    FormControl,
    InputLabel,
    Select,
    MenuItem,
    Divider,
} from '@mui/material';
import DirectionsCarIcon from '@mui/icons-material/DirectionsCar';
import CalculateIcon from '@mui/icons-material/Calculate';
import SendIcon from '@mui/icons-material/Send';
import DownloadIcon from '@mui/icons-material/Download';
import { formatCurrency } from '../utils/calculations';

const AutoCreditCalculator = () => {
    const [formData, setFormData] = useState({
        carCost: 1500000,
        initialPayment: 300000,
        termYears: 5,
        email: '',
        carType: 'new',
        loanType: 'standard',
    });

    const [results, setResults] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    // Процентные ставки в зависимости от типа авто и кредита
    const getInterestRate = () => {
        const { carType, loanType } = formData;
        let baseRate = 3.5; // Базовая ставка из ТЗ

        // Корректировка ставки в зависимости от типа авто
        if (carType === 'used') baseRate += 1.5;
        if (carType === 'premium') baseRate -= 0.5;

        // Корректировка в зависимости от типа кредита
        if (loanType === 'express') baseRate += 2;
        if (loanType === 'family') baseRate -= 0.3;

        return baseRate;
    };

    const calculateAutoCredit = () => {
        const { carCost, initialPayment, termYears } = formData;
        const annualRate = getInterestRate();

        // Расчет аналогичен ипотеке, но с другими параметрами
        const loanAmount = carCost - initialPayment;

        // Проверка минимального взноса (15%)
        const minPayment = carCost * 0.15;
        if (initialPayment < minPayment) {
            setError(`Минимальный первоначальный взнос: ${formatCurrency(minPayment)} (15%)`);
            return null;
        }

        // Ежемесячная процентная ставка
        const monthlyRate = annualRate / 12 / 100;

        // Общее количество платежей
        const totalPayments = termYears * 12;

        // Общая ставка (1 + месячная ставка) ^ срок в месяцах
        const totalRate = Math.pow(1 + monthlyRate, totalPayments);

        // Ежемесячный платеж
        const monthlyPayment = loanAmount * monthlyRate * totalRate / (totalRate - 1);

        // Общая сумма выплат
        const totalPayment = monthlyPayment * totalPayments;

        // Переплата
        const overpayment = totalPayment - loanAmount;

        // Страховка (примерно 0.5% от стоимости в месяц)
        const insurance = carCost * 0.005 / 12;

        // Общий ежемесячный платеж (кредит + страховка)
        const totalMonthlyPayment = monthlyPayment + insurance;

        // Необходимый доход (платеж × 2)
        const requiredIncome = totalMonthlyPayment * 2;

        return {
            loanAmount,
            monthlyRate,
            totalRate,
            monthlyPayment: Math.round(monthlyPayment),
            totalPayment: Math.round(totalPayment),
            overpayment: Math.round(overpayment),
            insurance: Math.round(insurance),
            totalMonthlyPayment: Math.round(totalMonthlyPayment),
            requiredIncome: Math.round(requiredIncome),
            annualRate,
            termYears,
            carCost,
            initialPayment,
            carType: formData.carType,
            loanType: formData.loanType,
        };
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: name === 'carType' || name === 'loanType' ? value : parseFloat(value) || 0,
        }));
        setError('');
    };

    const handleSliderChange = (name) => (e, value) => {
        setFormData(prev => ({
            ...prev,
            [name]: value,
        }));
        setError('');
    };

    const handleCalculate = () => {
        try {
            setLoading(true);
            setError('');

            const calculation = calculateAutoCredit();
            if (calculation) {
                setResults(calculation);
                setSuccess('Расчет выполнен успешно!');
            }

        } catch (err) {
            setError('Ошибка при расчете: ' + err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleSendEmail = () => {
        if (!formData.email) {
            setError('Введите email для отправки результатов');
            return;
        }
        setSuccess('Результаты отправлены на email!');
    };

    const handleSavePDF = () => {
        setSuccess('PDF документ сгенерирован и сохранен!');
    };

    const loanAmount = formData.carCost - formData.initialPayment;
    const annualRate = getInterestRate();
    const minPayment = formData.carCost * 0.15;

    return (
        <Container maxWidth="lg">
            <Paper elevation={3} sx={{ p: 4, mt: 4 }}>
                <Typography variant="h4" gutterBottom sx={{ mb: 4, color: 'primary.main' }}>
                    <DirectionsCarIcon sx={{ verticalAlign: 'middle', mr: 2 }} />
                    Калькулятор автокредита
                </Typography>

                {error && <Alert severity="error" sx={{ mb: 3 }}>{error}</Alert>}
                {success && <Alert severity="success" sx={{ mb: 3 }}>{success}</Alert>}

                <Grid container spacing={4}>
                    {/* Левая колонка - Ввод данных */}
                    <Grid item xs={12} md={6}>
                        <Box component="form" noValidate autoComplete="off">
                            <Typography variant="h6" gutterBottom sx={{ mb: 3, color: 'secondary.main' }}>
                                Параметры автокредита
                            </Typography>

                            {/* Тип автомобиля */}
                            <FormControl fullWidth margin="normal">
                                <InputLabel>Тип автомобиля</InputLabel>
                                <Select
                                    name="carType"
                                    value={formData.carType}
                                    onChange={handleInputChange}
                                    label="Тип автомобиля"
                                >
                                    <MenuItem value="new">Новый автомобиль</MenuItem>
                                    <MenuItem value="used">Автомобиль с пробегом</MenuItem>
                                    <MenuItem value="premium">Премиальный автомобиль</MenuItem>
                                </Select>
                            </FormControl>

                            {/* Тип кредита */}
                            <FormControl fullWidth margin="normal">
                                <InputLabel>Тип кредита</InputLabel>
                                <Select
                                    name="loanType"
                                    value={formData.loanType}
                                    onChange={handleInputChange}
                                    label="Тип кредита"
                                >
                                    <MenuItem value="standard">Стандартный</MenuItem>
                                    <MenuItem value="express">Экспресс-кредит</MenuItem>
                                    <MenuItem value="family">Семейный кредит</MenuItem>
                                </Select>
                            </FormControl>

                            <Divider sx={{ my: 3 }} />

                            {/* Стоимость авто */}
                            <TextField
                                fullWidth
                                label="Стоимость автомобиля, ₽"
                                name="carCost"
                                type="number"
                                value={formData.carCost}
                                onChange={handleInputChange}
                                margin="normal"
                                InputProps={{
                                    inputProps: { min: 500000, step: 50000 }
                                }}
                            />

                            {/* Первоначальный взнос */}
                            <Box sx={{ mt: 3 }}>
                                <Typography gutterBottom>
                                    Первоначальный взнос: {formatCurrency(formData.initialPayment)}
                                    {formData.initialPayment < minPayment && (
                                        <Typography variant="caption" color="error" sx={{ ml: 2 }}>
                                            (минимум: {formatCurrency(minPayment)})
                                        </Typography>
                                    )}
                                </Typography>
                                <Slider
                                    value={formData.initialPayment}
                                    onChange={handleSliderChange('initialPayment')}
                                    min={0}
                                    max={formData.carCost}
                                    step={50000}
                                    valueLabelDisplay="auto"
                                    valueLabelFormat={(value) => formatCurrency(value)}
                                    marks={[
                                        { value: minPayment, label: '15%' },
                                        { value: formData.carCost * 0.5, label: '50%' },
                                    ]}
                                />
                                <Typography variant="caption" color="text.secondary">
                                    Минимальный взнос: 15% ({formatCurrency(minPayment)})
                                </Typography>
                            </Box>

                            {/* Срок кредита */}
                            <Box sx={{ mt: 4 }}>
                                <Typography gutterBottom>
                                    Срок кредита: {formData.termYears} лет
                                </Typography>
                                <Slider
                                    value={formData.termYears}
                                    onChange={handleSliderChange('termYears')}
                                    min={1}
                                    max={7}
                                    valueLabelDisplay="auto"
                                    valueLabelFormat={(value) => `${value} лет`}
                                    marks={[
                                        { value: 1, label: '1 год' },
                                        { value: 3, label: '3 года' },
                                        { value: 5, label: '5 лет' },
                                        { value: 7, label: '7 лет' },
                                    ]}
                                />
                            </Box>

                            <TextField
                                fullWidth
                                label="Email для отправки результатов"
                                name="email"
                                type="email"
                                value={formData.email}
                                onChange={handleInputChange}
                                margin="normal"
                                sx={{ mt: 3 }}
                                placeholder="Ваш email для получения расчета"
                            />

                            <Box sx={{ mt: 3, display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                                <Button
                                    variant="contained"
                                    size="large"
                                    onClick={handleCalculate}
                                    disabled={loading || loanAmount <= 0}
                                    startIcon={<CalculateIcon />}
                                    sx={{ flexGrow: 1 }}
                                >
                                    Рассчитать автокредит
                                </Button>

                                {results && (
                                    <>
                                        <Button
                                            variant="outlined"
                                            size="large"
                                            onClick={handleSendEmail}
                                            disabled={!formData.email}
                                            startIcon={<SendIcon />}
                                        >
                                            Отправить
                                        </Button>
                                        <Button
                                            variant="outlined"
                                            size="large"
                                            onClick={handleSavePDF}
                                            startIcon={<DownloadIcon />}
                                        >
                                            Сохранить PDF
                                        </Button>
                                    </>
                                )}
                            </Box>
                        </Box>

                        {/* Информация о ставках */}
                        <Box sx={{ mt: 4, p: 3, bgcolor: 'info.light', borderRadius: 2 }}>
                            <Typography variant="subtitle1" gutterBottom>
                                <strong>Информация о процентных ставках:</strong>
                            </Typography>
                            <Typography variant="body2">
                                • Новый автомобиль: 3.5% годовых<br />
                                • С пробегом: +1.5% к базовой ставке<br />
                                • Премиальный: -0.5% к базовой ставке<br />
                                • Экспресс-кредит: +2% к ставке<br />
                                • Семейный кредит: -0.3% к ставке
                            </Typography>
                        </Box>
                    </Grid>

                    {/* Правая колонка - Результаты */}
                    <Grid item xs={12} md={6}>
                        <Typography variant="h6" gutterBottom sx={{ mb: 3, color: 'secondary.main' }}>
                            Результаты расчета
                        </Typography>

                        <Card sx={{ bgcolor: 'grey.50', mb: 3 }}>
                            <CardContent>
                                <Grid container spacing={2}>
                                    <Grid item xs={6}>
                                        <Typography variant="body2" color="text.secondary">
                                            Сумма кредита:
                                        </Typography>
                                        <Typography variant="h6">
                                            {formatCurrency(loanAmount)}
                                        </Typography>
                                    </Grid>
                                    <Grid item xs={6}>
                                        <Typography variant="body2" color="text.secondary">
                                            Процентная ставка:
                                        </Typography>
                                        <Typography variant="h6" color="secondary.main">
                                            {annualRate.toFixed(1)}% годовых
                                        </Typography>
                                    </Grid>
                                    <Grid item xs={6}>
                                        <Typography variant="body2" color="text.secondary">
                                            Тип авто:
                                        </Typography>
                                        <Typography variant="body1">
                                            {formData.carType === 'new' ? 'Новый' :
                                                formData.carType === 'used' ? 'С пробегом' : 'Премиальный'}
                                        </Typography>
                                    </Grid>
                                    <Grid item xs={6}>
                                        <Typography variant="body2" color="text.secondary">
                                            Срок кредита:
                                        </Typography>
                                        <Typography variant="body1">
                                            {formData.termYears} лет ({formData.termYears * 12} месяцев)
                                        </Typography>
                                    </Grid>
                                </Grid>
                            </CardContent>
                        </Card>

                        {results && (
                            <Box>
                                <Grid container spacing={2}>
                                    {/* Основной платеж */}
                                    <Grid item xs={12}>
                                        <Card sx={{ bgcolor: 'secondary.light', color: 'white' }}>
                                            <CardContent>
                                                <Typography variant="body2">
                                                    Ежемесячный платеж по кредиту:
                                                </Typography>
                                                <Typography variant="h4">
                                                    {formatCurrency(results.monthlyPayment)}
                                                </Typography>
                                            </CardContent>
                                        </Card>
                                    </Grid>

                                    {/* Страховка */}
                                    <Grid item xs={6}>
                                        <Card>
                                            <CardContent>
                                                <Typography variant="body2" color="text.secondary">
                                                    Страховка (КАСКО):
                                                </Typography>
                                                <Typography variant="h6">
                                                    {formatCurrency(results.insurance)}/мес
                                                </Typography>
                                            </CardContent>
                                        </Card>
                                    </Grid>

                                    {/* Общий платеж */}
                                    <Grid item xs={6}>
                                        <Card sx={{ bgcolor: 'primary.light', color: 'white' }}>
                                            <CardContent>
                                                <Typography variant="body2">
                                                    Общий платеж:
                                                </Typography>
                                                <Typography variant="h6">
                                                    {formatCurrency(results.totalMonthlyPayment)}/мес
                                                </Typography>
                                            </CardContent>
                                        </Card>
                                    </Grid>

                                    {/* Итоги */}
                                    <Grid item xs={6}>
                                        <Card>
                                            <CardContent>
                                                <Typography variant="body2" color="text.secondary">
                                                    Общая сумма выплат:
                                                </Typography>
                                                <Typography variant="h6">
                                                    {formatCurrency(results.totalPayment)}
                                                </Typography>
                                            </CardContent>
                                        </Card>
                                    </Grid>

                                    <Grid item xs={6}>
                                        <Card>
                                            <CardContent>
                                                <Typography variant="body2" color="text.secondary">
                                                    Переплата по кредиту:
                                                </Typography>
                                                <Typography variant="h6" color="error.main">
                                                    {formatCurrency(results.overpayment)}
                                                </Typography>
                                            </CardContent>
                                        </Card>
                                    </Grid>

                                    {/* Необходимый доход */}
                                    <Grid item xs={12}>
                                        <Card sx={{ bgcolor: 'warning.light' }}>
                                            <CardContent>
                                                <Typography variant="body2" color="text.secondary">
                                                    Рекомендуемый ежемесячный доход:
                                                </Typography>
                                                <Typography variant="h5">
                                                    {formatCurrency(results.requiredIncome)}
                                                </Typography>
                                                <Typography variant="caption">
                                                    (общий платеж × 2)
                                                </Typography>
                                            </CardContent>
                                        </Card>
                                    </Grid>
                                </Grid>

                                {/* График платежей (упрощенный) */}
                                <Box sx={{ mt: 3, p: 2, bgcolor: 'grey.100', borderRadius: 1 }}>
                                    <Typography variant="subtitle1" gutterBottom>
                                        <strong>Пример графика платежей (первые 6 месяцев):</strong>
                                    </Typography>
                                    <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 1 }}>
                                        {[1, 2, 3, 4, 5, 6].map(month => (
                                            <Box key={month} sx={{ textAlign: 'center' }}>
                                                <Typography variant="caption">Месяц {month}</Typography>
                                                <Typography variant="body2">
                                                    {formatCurrency(results.monthlyPayment)}
                                                </Typography>
                                            </Box>
                                        ))}
                                    </Box>
                                </Box>

                                {/* Расчет эффективной ставки */}
                                <Box sx={{ mt: 2, p: 2, bgcolor: 'success.light', borderRadius: 1 }}>
                                    <Typography variant="body2">
                                        <strong>Эффективная процентная ставка:</strong> ~{(annualRate * 1.1).toFixed(1)}% годовых<br />
                                        <small>С учетом страховки и дополнительных расходов</small>
                                    </Typography>
                                </Box>
                            </Box>
                        )}

                        {/* Подсказки */}
                        {!results && (
                            <Box sx={{ mt: 4, p: 3, border: '1px dashed', borderColor: 'divider', borderRadius: 2 }}>
                                <Typography variant="subtitle1" gutterBottom>
                                    Советы по выбору автокредита:
                                </Typography>
                                <Typography variant="body2">
                                    1. При увеличении первоначального взноса снижается ежемесячный платеж<br />
                                    2. Более короткий срок кредита уменьшает переплату<br />
                                    3. Новые автомобили имеют более низкие процентные ставки<br />
                                    4. Не забудьте учесть расходы на страховку КАСКО
                                </Typography>
                            </Box>
                        )}
                    </Grid>
                </Grid>
            </Paper>
        </Container>
    );
};

export default AutoCreditCalculator;
